<?php require_once __DIR__.'/includes/db.php'; require_login(); page_header(tr('questions'),'questions'); $q=trim($_GET['q']??''); $items=[]; if(table_exists('hier_questions')){ $where='';$params=[]; if($q!==''){ $where='WHERE h.question_text LIKE ? OR st.discipline_name LIKE ? OR st.title LIKE ?'; $params=['%'.$q.'%','%'.$q.'%','%'.$q.'%']; } $items=rows("SELECT h.question_id,h.question_text,h.question_type,h.max_score,st.discipline_name,st.course_number,st.title topic_title FROM hier_questions h LEFT JOIN ai_syllabus_topics st ON st.syllabus_topic_id=h.syllabus_topic_id $where ORDER BY h.question_id DESC LIMIT 500",$params); } ?><div class="card"><div class="toolbar"><h2><?=h(tr('question_bank'))?></h2><form method="get"><input type="hidden" name="lang" value="<?=h(current_lang())?>"><input class="input" name="q" value="<?=h($q)?>" placeholder="<?=h(tr('search_placeholder'))?>"><button class="btn"><?=h(tr('search'))?></button></form></div><div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th><?=h(tr('text'))?></th><th><?=h(tr('discipline'))?></th><th><?=h(tr('course'))?></th><th><?=h(tr('type'))?></th><th><?=h(tr('topics'))?></th></tr></thead><tbody><?php foreach($items as $r):?><tr><td><?=h($r['question_id'])?></td><td><?=h($r['question_text'])?></td><td><?=h($r['discipline_name']??'')?></td><td><?=h($r['course_number']??'')?></td><td><span class="pill"><?=h($r['question_type']??'')?></span></td><td><?=h($r['topic_title']??'')?></td></tr><?php endforeach;?><?php if(!$items):?><tr><td colspan="6" class="empty"><?=h(tr('no_data'))?></td></tr><?php endif;?></tbody></table></div></div><?php page_footer(); ?>